import React, { useState, useEffect } from "react";
import { Navigation } from "./components/navigation";
import { Header } from "./components/header";
import { Services } from "./components/services";
import { WhyChoose } from "./components/whyChoose";
import { Gallery } from "./components/gallery";
import { Process } from "./components/process";
import { CtaBanner } from "./components/ctaBanner";
import { Contact } from "./components/contact";
import JsonData from "./data/data.json";
import SmoothScroll from "smooth-scroll";
import "./App.css";

export const scroll = new SmoothScroll('a[href*="#"]', {
  speed: 1000,
  speedAsDuration: true,
});

const App = () => {
  const [landingPageData, setLandingPageData] = useState({});
  useEffect(() => {
    setLandingPageData(JsonData);
  }, []);

  const headerLogo = landingPageData.Header?.logo;

  return (
    <div className="55lab-site">
      <Navigation logo={headerLogo} />
      <Header data={landingPageData.Header} />
      <Services data={landingPageData.Services} />
      <WhyChoose data={landingPageData.Why} />
      <Gallery data={landingPageData.Portfolio} />
      <Process data={landingPageData.Process} />
      <CtaBanner data={landingPageData.Cta} />
      <Contact data={landingPageData.Contact} logo={headerLogo} />
    </div>
  );
};

export default App;
